// js/dom-manager.js
class DOMManager {
    constructor() {
        this.preventAllRefresh();
        this.initGlobalHandlers();
    }
    
    // منع جميع سلوكيات Refresh
    preventAllRefresh() {
        // 1. منع سلوك الفورمات
        document.addEventListener('submit', (e) => {
            console.warn('Form submit prevented by DOMManager');
            e.preventDefault();
            e.stopPropagation();
            return false;
        }, { capture: true });
        
        // 2. ضبط جميع الأزرار ليكون type="button"
        this.fixAllButtons();
        
        // 3. مراقبة DOM للتأكد من بقاء الأزرار آمنة
        this.observeDOMChanges();
        
        // 4. منع Enter في حقول الإدخال
        this.preventEnterSubmit();
        
        // 5. منع قبل إغلاق الصفحة
        this.preventUnload();
    }
    
    // إصلاح جميع الأزرار
    fixAllButtons() {
        document.querySelectorAll('button').forEach(btn => {
            if (!btn.hasAttribute('type') || btn.type === 'submit') {
                btn.type = 'button';
                btn.setAttribute('data-fixed', 'true');
            }
        });
    }
    
    // مراقبة تغييرات DOM
    observeDOMChanges() {
        const observer = new MutationObserver((mutations) => {
            mutations.forEach((mutation) => {
                if (mutation.addedNodes.length) {
                    setTimeout(() => this.fixAllButtons(), 50);
                }
            });
        });
        
        observer.observe(document.body, {
            childList: true,
            subtree: true
        });
    }
    
    // منع Enter من إرسال الفورم
    preventEnterSubmit() {
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Enter') {
                const target = e.target;
                if (target.tagName === 'INPUT' || 
                    target.tagName === 'TEXTAREA' || 
                    target.tagName === 'SELECT') {
                    
                    // إذا كان داخل فورم، امنعه
                    if (target.closest('form')) {
                        e.preventDefault();
                        e.stopPropagation();
                        console.log('Enter key prevented in form field');
                    }
                }
            }
        });
    }
    
    // إضافة مستمع حدث آمن
    addSafeListener(selector, event, handler) {
        document.addEventListener(event, (e) => {
            const target = e.target.closest(selector);
            if (target) {
                e.preventDefault();
                e.stopPropagation();
                handler.call(target, e);
            }
        });
    }
    
    // منع إغلاق الصفحة
    preventUnload() {
        window.addEventListener('beforeunload', (e) => {
            // لا تفعل شيئاً - فقط تمنع الرسالة الافتراضية
        });
    }
    
    // تهيئة المعالجين العامين
    initGlobalHandlers() {
        // معالج النقر العام
        document.addEventListener('click', (e) => {
            const target = e.target;
            
            // منع النقر على أي زر
            if (target.tagName === 'BUTTON' || 
                target.closest('button')) {
                e.preventDefault();
                e.stopPropagation();
            }
            
            // منع النقر على روابط فارغة
            if (target.tagName === 'A' && 
                (target.getAttribute('href') === '#' || 
                 target.getAttribute('href') === 'javascript:void(0)')) {
                e.preventDefault();
                e.stopPropagation();
            }
        }, { capture: true });
    }
    
    // عرض رسالة تحذير
    showWarning(message) {
        console.warn(`[DOMManager] ${message}`);
    }
}

// إنشاء نسخة واحدة فقط
let domManagerInstance = null;

function getDOMManager() {
    if (!domManagerInstance) {
        domManagerInstance = new DOMManager();
    }
    return domManagerInstance;
}

// التصدير
if (typeof module !== 'undefined' && module.exports) {
    module.exports = { DOMManager, getDOMManager };
}